const trigger = $('Set: Store Trigger Data').first().json;

function parseEmailJson(nodeOutput, emailNr) {
  const raw = nodeOutput.text || nodeOutput.output || nodeOutput.response || '';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch(e) {
    if (emailNr === 1) {
      return { betreff_varianten: ['Follow-up', 'Kurze Frage', 'Idee fuer ' + (trigger.unternehmen || 'Ihr Unternehmen')], text: raw || '' };
    } else {
      return { betreff: 'Follow-up: ' + (trigger.unternehmen || 'Ihr Unternehmen'), text: raw || '' };
    }
  }
}

const e1 = parseEmailJson($('LLM: Email 1 BASHO').first().json, 1);
const e2 = parseEmailJson($('LLM: Email 2 SPIN').first().json, 2);
const e3 = parseEmailJson($('LLM: Email 3 Klaff').first().json, 3);
const e4 = parseEmailJson($('LLM: Email 4 Gitomer').first().json, 4);

return [{ json: {
  lead_id: trigger.lead_id,
  emails: [
    { nr: 1, betreff_varianten: e1.betreff_varianten || ['Betreff A', 'Betreff B', 'Betreff C'], text: e1.text || '' },
    { nr: 2, betreff: e2.betreff || 'Follow-up', text: e2.text || '' },
    { nr: 3, betreff: e3.betreff || 'Follow-up', text: e3.text || '' },
    { nr: 4, betreff: e4.betreff || 'Letzte Nachricht', text: e4.text || '' }
  ]
}}];
